11→pub struct ChidArgs {
12→    /// Revision to look up (default: @)
13→    #[arg(short, long, default_value = "@")]
14→    pub revision: String,
15→
16→    /// Path to jj repo (default: current directory)
17→    #[arg(short = 'R', long, default_value = ".")]
18→    pub repo: PathBuf,
19→
20→    /// Maximum number of changeIDs to show
21→    #[arg(short, long)]
22→    pub limit: Option<usize>,
23→}
