25→pub fn chid(args: &ChidArgs) -> Result<(), Box<dyn std::error::Error>> {
26→    let (workspace, repo) = common::load_repo(&args.repo)?;
27→
28→    let limit = args.limit.unwrap_or(1);
29→
30→    let revset_str = if limit > 1 {
31→        format!("ancestors({})", args.revision)
32→    } else {
33→        args.revision.clone()
34→    };
35→
36→    let commit_ids = common::resolve_revset(&workspace, &repo, &revset_str)?;
37→
38→    if commit_ids.is_empty() {
39→        return Err(format!("no commit found for revision '{}'", args.revision).into());
40→    }
41→
42→    let root_commit_id = repo.store().root_commit_id().clone();
43→
44→    let mut count = 0;
45→    for commit_id in &commit_ids {
46→        if *commit_id == root_commit_id {
47→            continue;
48→        }
49→        let commit = repo.store().get_commit(commit_id)?;
50→        let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
51→        let change_short = &change_hex[..change_hex.len().min(12)];
52→
53→        println!("{change_short}");
54→
55→        count += 1;
56→        if count >= limit {
57→            break;
58→        }
59→    }
60→
61→    Ok(())
62→}
